{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleTryCatchTypeAliasTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a function expression body starting with try and catch on new line`() {
        val code =
            """
            fun test() = try {
                1
            }
            catch(_: Throwable) {
                2
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a typealias with type reference on new line`() {
        val code =
            """
            typealias Foo =
                HashMap<Bar, Baz?>
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a try-catch-finally where try is indented`() {
        val code =
            """
            fun test() {
                try {
                    1
                } catch (e: Exception) {
                    2
                } finally {
                    3
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a try-catch-finally where catch and finally are on new lines and indented`() {
        val code =
            """
            fun test() {
                try {
                    1
                }
                catch (e: Exception) {
                    2
                }
                finally {
                    3
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
